import{_ as t,c as d,o,ag as a}from"./chunks/framework.Bw-5EFTY.js";const f=JSON.parse('{"title":"DAG Node Specification","description":"","frontmatter":{},"headers":[],"relativePath":"packages/dag-node/docs/SPEC.md","filePath":"packages/dag-node/docs/SPEC.md"}'),c={name:"packages/dag-node/docs/SPEC.md"};function r(i,e,n,s,l,h){return o(),d("div",null,e[0]||(e[0]=[a(`<h1 id="dag-node-specification" tabindex="-1">DAG Node Specification <a class="header-anchor" href="#dag-node-specification" aria-label="Permalink to &quot;DAG Node Specification&quot;">​</a></h1><h2 id="scope" tabindex="-1">Scope <a class="header-anchor" href="#scope" aria-label="Permalink to &quot;Scope&quot;">​</a></h2><p><code>@robota-sdk/dag-node</code> is the node authoring infrastructure package for the Robota DAG system. It provides the abstract base class, lifecycle wrappers, registries, IO accessors, value objects, and helper functions that node implementors use to build concrete node definitions. This package sits between <code>dag-core</code> (which owns the domain contracts and interfaces) and <code>dag-nodes</code> (which contains the concrete node implementations).</p><h2 id="boundaries" tabindex="-1">Boundaries <a class="header-anchor" href="#boundaries" aria-label="Permalink to &quot;Boundaries&quot;">​</a></h2><ul><li><strong>No domain contracts.</strong> Interfaces (<code>IDagNodeDefinition</code>, <code>INodeLifecycle</code>, <code>INodeTaskHandler</code>, etc.), type definitions, state machines, and error builders belong to <code>@robota-sdk/dag-core</code>.</li><li><strong>No concrete node implementations.</strong> Specific node types (e.g., <code>llm-text-openai</code>, <code>image-source</code>) belong to <code>@robota-sdk/dag-nodes</code>.</li><li><strong>No orchestration or runtime.</strong> DAG scheduling, worker execution, and run coordination belong to <code>dag-runtime</code>, <code>dag-worker</code>, <code>dag-scheduler</code>.</li><li><strong>No API layer.</strong> HTTP/REST composition belongs to application packages.</li><li><strong>No execution engine or lifecycle runner.</strong> The <code>NodeLifecycleRunner</code> and <code>LifecycleTaskExecutorPort</code> belong to <code>@robota-sdk/dag-core</code>.</li></ul><h2 id="architecture-overview" tabindex="-1">Architecture Overview <a class="header-anchor" href="#architecture-overview" aria-label="Permalink to &quot;Architecture Overview&quot;">​</a></h2><h3 id="layer-structure" tabindex="-1">Layer Structure <a class="header-anchor" href="#layer-structure" aria-label="Permalink to &quot;Layer Structure&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>dag-node/</span></span>
<span class="line"><span>  src/</span></span>
<span class="line"><span>    lifecycle/           -- Abstract base class, IO accessor, lifecycle wrappers, factory</span></span>
<span class="line"><span>    registry/            -- Static manifest registry</span></span>
<span class="line"><span>    schemas/             -- Zod schemas for media references</span></span>
<span class="line"><span>    utils/               -- Node descriptor (buildConfigSchema)</span></span>
<span class="line"><span>    value-objects/       -- MediaReference immutable value object</span></span>
<span class="line"><span>    node-definition-assembly.ts -- buildNodeDefinitionAssembly factory</span></span>
<span class="line"><span>    port-definition-helpers.ts  -- Binary port definition factory and presets</span></span>
<span class="line"><span>    __tests__/           -- Unit tests</span></span></code></pre></div><h3 id="design-patterns" tabindex="-1">Design Patterns <a class="header-anchor" href="#design-patterns" aria-label="Permalink to &quot;Design Patterns&quot;">​</a></h3><ul><li><strong>Abstract template pattern</strong>: <code>AbstractNodeDefinition&lt;TSchema&gt;</code> provides a config-parsing template that automatically validates node config against a Zod schema before delegating to <code>*WithConfig</code> methods. This ensures every lifecycle step receives a typed, validated config object.</li><li><strong>Adapter pattern</strong>: <code>RegisteredNodeLifecycle</code> wraps an <code>INodeTaskHandler</code> (partial interface) into a full <code>INodeLifecycle</code> with base port validation for inputs and outputs.</li><li><strong>Factory pattern</strong>: <code>StaticNodeLifecycleFactory</code> creates <code>INodeLifecycle</code> instances by looking up handlers in a registry and wrapping them.</li><li><strong>Registry pattern</strong>: <code>StaticNodeManifestRegistry</code> and <code>StaticNodeTaskHandlerRegistry</code> provide in-memory lookup for node manifests and task handlers by node type.</li><li><strong>Value object pattern</strong>: <code>MediaReference</code> is an immutable object with factory methods (<code>fromAssetReference</code>, <code>fromBinary</code>, <code>fromCandidate</code>) and no public constructor.</li><li><strong>Result pattern</strong>: All operations that can fail return <code>TResult&lt;T, IDagError&gt;</code> instead of throwing.</li></ul><h2 id="type-ownership" tabindex="-1">Type Ownership <a class="header-anchor" href="#type-ownership" aria-label="Permalink to &quot;Type Ownership&quot;">​</a></h2><p>Types owned by this package (defined here, not imported):</p><table tabindex="0"><thead><tr><th>Type</th><th>Location</th><th>Purpose</th></tr></thead><tbody><tr><td><code>IMediaReferenceCandidate</code></td><td><code>value-objects/media-reference.ts</code></td><td>Loosely-typed input for creating a <code>MediaReference</code></td></tr><tr><td><code>IParsedBinaryValue</code></td><td><code>lifecycle/binary-value-parser.ts</code></td><td>Validated binary port value with kind, MIME type, and URI</td></tr><tr><td><code>IBinaryPortPreset</code></td><td><code>port-definition-helpers.ts</code></td><td>Pre-configured binary kind and MIME type combination</td></tr><tr><td><code>IBinaryPortDefinitionInput</code></td><td><code>port-definition-helpers.ts</code></td><td>Input for <code>createBinaryPortDefinition</code> factory</td></tr></tbody></table><p>Types imported from <code>@robota-sdk/dag-core</code> (not owned):</p><table tabindex="0"><thead><tr><th>Type</th><th>Purpose</th></tr></thead><tbody><tr><td><code>IDagNodeDefinition</code></td><td>Interface that <code>AbstractNodeDefinition</code> implements</td></tr><tr><td><code>INodeLifecycle</code></td><td>Interface that <code>RegisteredNodeLifecycle</code> implements</td></tr><tr><td><code>INodeLifecycleFactory</code></td><td>Interface that <code>StaticNodeLifecycleFactory</code> implements</td></tr><tr><td><code>INodeTaskHandler</code></td><td>Partial lifecycle handler interface</td></tr><tr><td><code>INodeTaskHandlerRegistry</code></td><td>Interface that <code>StaticNodeTaskHandlerRegistry</code> implements</td></tr><tr><td><code>INodeManifestRegistry</code></td><td>Interface that <code>StaticNodeManifestRegistry</code> implements</td></tr><tr><td><code>INodeManifest</code></td><td>Node registration manifest</td></tr><tr><td><code>INodeExecutionContext</code></td><td>Execution context passed to lifecycle methods</td></tr><tr><td><code>ICostEstimate</code></td><td>Cost estimate returned from <code>estimateCost</code></td></tr><tr><td><code>TResult&lt;T, E&gt;</code></td><td>Discriminated union result type</td></tr><tr><td><code>IDagError</code></td><td>Canonical error structure</td></tr><tr><td><code>TPortPayload</code>, <code>TPortValue</code></td><td>Port value types</td></tr><tr><td><code>IPortDefinition</code></td><td>Port schema definition</td></tr><tr><td><code>IPortBinaryValue</code></td><td>Binary port value structure</td></tr><tr><td><code>TAssetReference</code>, <code>TAssetReferenceType</code>, <code>TBinaryKind</code></td><td>Asset and binary kind types</td></tr></tbody></table><h2 id="public-api-surface" tabindex="-1">Public API Surface <a class="header-anchor" href="#public-api-surface" aria-label="Permalink to &quot;Public API Surface&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Export</th><th>Kind</th><th>Description</th></tr></thead><tbody><tr><td><code>AbstractNodeDefinition&lt;TSchema&gt;</code></td><td>Abstract class</td><td>Base class for all node implementations; parses config via Zod, delegates to <code>*WithConfig</code> template methods</td></tr><tr><td><code>NodeIoAccessor</code></td><td>Class</td><td>Typed accessor for reading input values and building output payloads within node execution</td></tr><tr><td><code>RegisteredNodeLifecycle</code></td><td>Class</td><td>Wraps an <code>INodeTaskHandler</code> into a full <code>INodeLifecycle</code> with base port validation</td></tr><tr><td><code>StaticNodeLifecycleFactory</code></td><td>Class</td><td>Creates <code>INodeLifecycle</code> instances from a static handler registry</td></tr><tr><td><code>StaticNodeTaskHandlerRegistry</code></td><td>Class</td><td>In-memory registry of <code>INodeTaskHandler</code> by node type</td></tr><tr><td><code>StaticNodeManifestRegistry</code></td><td>Class</td><td>In-memory registry of <code>INodeManifest</code> by node type</td></tr><tr><td><code>MediaReference</code></td><td>Value object</td><td>Immutable media reference with factory methods and conversion helpers</td></tr><tr><td><code>MediaReferenceSchema</code></td><td>Zod schema</td><td>Zod validation schema for media reference config</td></tr><tr><td><code>createMediaReferenceConfigSchema</code></td><td>Function</td><td>Creates a Zod schema wrapping <code>MediaReferenceSchema</code> under an <code>asset</code> key</td></tr><tr><td><code>parseBinaryValue</code></td><td>Function</td><td>Parses and validates a raw port value as a binary payload</td></tr><tr><td><code>createBinaryPortDefinition</code></td><td>Function</td><td>Creates an <code>IPortDefinition</code> for binary ports using a preset</td></tr><tr><td><code>BINARY_PORT_PRESETS</code></td><td>Constant</td><td>Predefined binary port presets (IMAGE_PNG, IMAGE_COMMON, VIDEO_MP4, etc.)</td></tr><tr><td><code>buildNodeDefinitionAssembly</code></td><td>Function</td><td>Builds manifests and handler registry from an array of <code>IDagNodeDefinition</code></td></tr><tr><td><code>buildConfigSchema</code></td><td>Function</td><td>Converts a Zod schema to JSON Schema 7 for node config</td></tr><tr><td><code>createStaticNodeLifecycleFactory</code></td><td>Function</td><td>Factory function that creates a <code>StaticNodeLifecycleFactory</code> from a handler map</td></tr></tbody></table><h2 id="extension-points" tabindex="-1">Extension Points <a class="header-anchor" href="#extension-points" aria-label="Permalink to &quot;Extension Points&quot;">​</a></h2><h3 id="abstractnodedefinition-tschema" tabindex="-1">AbstractNodeDefinition&lt;TSchema&gt; <a class="header-anchor" href="#abstractnodedefinition-tschema" aria-label="Permalink to &quot;AbstractNodeDefinition\\&lt;TSchema\\&gt;&quot;">​</a></h3><p>The primary extension point for node implementors. Concrete node classes must:</p><ol><li>Extend <code>AbstractNodeDefinition&lt;TSchema&gt;</code> where <code>TSchema</code> is a Zod schema type.</li><li>Declare <code>nodeType</code>, <code>displayName</code>, <code>category</code>, <code>inputs</code>, <code>outputs</code>, and <code>configSchemaDefinition</code>.</li><li>Implement <code>executeWithConfig(input, context, config)</code> -- the core execution logic.</li><li>Implement <code>estimateCostWithConfig(input, context, config)</code> -- cost estimation before execution.</li><li>Optionally override <code>initializeWithConfig</code>, <code>validateInputWithConfig</code>, <code>validateOutputWithConfig</code>, and <code>disposeWithConfig</code>.</li></ol><p>The base class automatically parses and validates node config against the Zod schema before delegating to any <code>*WithConfig</code> method. Config parse failures produce <code>DAG_VALIDATION_NODE_CONFIG_SCHEMA_INVALID</code> errors.</p><h3 id="nodeioaccessor" tabindex="-1">NodeIoAccessor <a class="header-anchor" href="#nodeioaccessor" aria-label="Permalink to &quot;NodeIoAccessor&quot;">​</a></h3><p>Provides typed input reading within node execution:</p><ul><li><code>requireInput(key)</code> / <code>requireInputString(key)</code> / <code>requireInputArray(key)</code> -- scalar and array access with validation errors.</li><li><code>requireInputBinary(key, kind?)</code> / <code>requireInputBinaryList(key, kind?, options?)</code> -- binary payload access with kind and MIME-type validation.</li><li><code>requireInputMediaReference(key, options?)</code> / <code>requireInputBinaryReference(key, kind?)</code> -- media reference access returning <code>MediaReference</code> value objects.</li><li><code>setOutput(key, value)</code> / <code>toOutput()</code> -- output assembly.</li></ul><h3 id="inodetaskhandler" tabindex="-1">INodeTaskHandler <a class="header-anchor" href="#inodetaskhandler" aria-label="Permalink to &quot;INodeTaskHandler&quot;">​</a></h3><p>A lighter alternative to full <code>INodeLifecycle</code>. Only <code>execute</code> is required; all other lifecycle methods are optional. The <code>RegisteredNodeLifecycle</code> wrapper fills in defaults and adds base port validation for handlers that omit <code>validateInput</code>/<code>validateOutput</code>.</p><h2 id="error-taxonomy" tabindex="-1">Error Taxonomy <a class="header-anchor" href="#error-taxonomy" aria-label="Permalink to &quot;Error Taxonomy&quot;">​</a></h2><p>All errors use codes and categories defined in <code>@robota-sdk/dag-core</code>. This package produces errors in the following categories:</p><h3 id="validation-errors-category-validation-retryable-false" tabindex="-1">Validation Errors (category: <code>validation</code>, retryable: <code>false</code>) <a class="header-anchor" href="#validation-errors-category-validation-retryable-false" aria-label="Permalink to &quot;Validation Errors (category: \`validation\`, retryable: \`false\`)&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Code</th><th>Source</th><th>Description</th></tr></thead><tbody><tr><td><code>DAG_VALIDATION_NODE_CONFIG_SCHEMA_INVALID</code></td><td><code>AbstractNodeDefinition</code></td><td>Node config fails Zod schema parse</td></tr><tr><td><code>DAG_VALIDATION_NODE_INPUT_MISSING</code></td><td><code>NodeIoAccessor</code></td><td>Required input key is missing</td></tr><tr><td><code>DAG_VALIDATION_NODE_INPUT_TYPE_MISMATCH</code></td><td><code>NodeIoAccessor</code>, <code>RegisteredNodeLifecycle</code></td><td>Input value type does not match port type</td></tr><tr><td><code>DAG_VALIDATION_NODE_INPUT_MIN_ITEMS_NOT_SATISFIED</code></td><td><code>NodeIoAccessor</code>, <code>RegisteredNodeLifecycle</code></td><td>List input has fewer items than minItems</td></tr><tr><td><code>DAG_VALIDATION_NODE_INPUT_MAX_ITEMS_EXCEEDED</code></td><td><code>NodeIoAccessor</code>, <code>RegisteredNodeLifecycle</code></td><td>List input has more items than maxItems</td></tr><tr><td><code>DAG_VALIDATION_NODE_REQUIRED_INPUT_MISSING</code></td><td><code>RegisteredNodeLifecycle</code></td><td>Required input port value is missing</td></tr><tr><td><code>DAG_VALIDATION_NODE_REQUIRED_OUTPUT_MISSING</code></td><td><code>RegisteredNodeLifecycle</code></td><td>Required output port value is missing</td></tr><tr><td><code>DAG_VALIDATION_NODE_OUTPUT_TYPE_MISMATCH</code></td><td><code>RegisteredNodeLifecycle</code></td><td>Output value type does not match port type</td></tr><tr><td><code>DAG_VALIDATION_NODE_OUTPUT_MIN_ITEMS_NOT_SATISFIED</code></td><td><code>RegisteredNodeLifecycle</code></td><td>List output has fewer items than minItems</td></tr><tr><td><code>DAG_VALIDATION_NODE_OUTPUT_MAX_ITEMS_EXCEEDED</code></td><td><code>RegisteredNodeLifecycle</code></td><td>List output has more items than maxItems</td></tr><tr><td><code>DAG_VALIDATION_NODE_LIFECYCLE_NOT_REGISTERED</code></td><td><code>StaticNodeLifecycleFactory</code></td><td>No lifecycle registered for node type</td></tr><tr><td><code>DAG_VALIDATION_MEDIA_REFERENCE_INVALID</code></td><td><code>MediaReference</code></td><td>Media reference structure is invalid</td></tr><tr><td><code>DAG_VALIDATION_MEDIA_REFERENCE_XOR_REQUIRED</code></td><td><code>MediaReference</code></td><td>Exactly one of assetId or uri must be provided</td></tr><tr><td><code>DAG_VALIDATION_MEDIA_REFERENCE_TYPE_MISMATCH</code></td><td><code>MediaReference</code></td><td>referenceType does not match provided fields</td></tr></tbody></table><h2 id="class-contract-registry" tabindex="-1">Class Contract Registry <a class="header-anchor" href="#class-contract-registry" aria-label="Permalink to &quot;Class Contract Registry&quot;">​</a></h2><h3 id="interface-implementations" tabindex="-1">Interface Implementations <a class="header-anchor" href="#interface-implementations" aria-label="Permalink to &quot;Interface Implementations&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Interface (Owner)</th><th>Implementor</th><th>Kind</th><th>Location</th></tr></thead><tbody><tr><td><code>IDagNodeDefinition</code> (dag-core)</td><td><code>AbstractNodeDefinition</code></td><td>abstract base</td><td><code>src/lifecycle/abstract-node-definition.ts</code></td></tr><tr><td><code>INodeLifecycle</code> (dag-core)</td><td><code>RegisteredNodeLifecycle</code></td><td>production</td><td><code>src/lifecycle/registered-node-lifecycle.ts</code></td></tr><tr><td><code>INodeLifecycleFactory</code> (dag-core)</td><td><code>StaticNodeLifecycleFactory</code></td><td>production</td><td><code>src/lifecycle/static-node-lifecycle-factory.ts</code></td></tr><tr><td><code>INodeManifestRegistry</code> (dag-core)</td><td><code>StaticNodeManifestRegistry</code></td><td>production</td><td><code>src/registry/static-node-manifest-registry.ts</code></td></tr><tr><td><code>INodeTaskHandlerRegistry</code> (dag-core)</td><td><code>StaticNodeTaskHandlerRegistry</code></td><td>production</td><td><code>src/lifecycle/default-node-task-handlers.ts</code></td></tr></tbody></table><h3 id="cross-package-consumers" tabindex="-1">Cross-Package Consumers <a class="header-anchor" href="#cross-package-consumers" aria-label="Permalink to &quot;Cross-Package Consumers&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Export (This Package)</th><th>Consumer Package</th><th>Notes</th></tr></thead><tbody><tr><td><code>AbstractNodeDefinition</code></td><td><code>dag-nodes</code> (11 node definitions)</td><td>Each implements <code>executeWithConfig</code> and <code>estimateCostWithConfig</code></td></tr><tr><td><code>NodeIoAccessor</code></td><td><code>dag-nodes</code> (11 node definitions)</td><td>Used for input reading and output assembly</td></tr><tr><td><code>MediaReference</code></td><td><code>dag-nodes</code> (media-handling nodes)</td><td>Used for asset reference handling</td></tr><tr><td><code>BINARY_PORT_PRESETS</code>, <code>createBinaryPortDefinition</code></td><td><code>dag-nodes</code> (binary-handling nodes)</td><td>Used for port definitions</td></tr><tr><td><code>buildNodeDefinitionAssembly</code></td><td><code>dag-runtime-server</code>, <code>dag-orchestrator-server</code></td><td>Builds manifests + handler map from node definitions</td></tr><tr><td><code>StaticNodeLifecycleFactory</code>, <code>StaticNodeTaskHandlerRegistry</code></td><td><code>dag-runtime-server</code></td><td>Creates lifecycle instances for node execution</td></tr></tbody></table><h2 id="dependencies" tabindex="-1">Dependencies <a class="header-anchor" href="#dependencies" aria-label="Permalink to &quot;Dependencies&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Dependency</th><th>Purpose</th></tr></thead><tbody><tr><td><code>@robota-sdk/dag-core</code></td><td>Domain contracts, interfaces, error builders, type definitions</td></tr><tr><td><code>zod</code></td><td>Runtime schema validation for node configs and media references</td></tr><tr><td><code>zod-to-json-schema</code></td><td>Converts Zod schemas to JSON Schema 7 for manifest <code>configSchema</code></td></tr></tbody></table><h2 id="test-strategy" tabindex="-1">Test Strategy <a class="header-anchor" href="#test-strategy" aria-label="Permalink to &quot;Test Strategy&quot;">​</a></h2><h3 id="current-test-files" tabindex="-1">Current Test Files <a class="header-anchor" href="#current-test-files" aria-label="Permalink to &quot;Current Test Files&quot;">​</a></h3><table tabindex="0"><thead><tr><th>File</th><th>Coverage</th></tr></thead><tbody><tr><td><code>__tests__/abstract-node-definition.test.ts</code></td><td>Config parsing, <code>*WithConfig</code> delegation, config validation error generation</td></tr><tr><td><code>__tests__/node-io-accessor.test.ts</code></td><td><code>requireInput*</code> methods, binary access, media reference access, output assembly</td></tr><tr><td><code>__tests__/registered-node-lifecycle.test.ts</code></td><td>Port validation (required ports, type matching, list constraints), handler delegation</td></tr><tr><td><code>__tests__/static-node-lifecycle-factory.test.ts</code></td><td>Factory creation from registry, missing handler error</td></tr><tr><td><code>__tests__/static-node-manifest-registry.test.ts</code></td><td>Manifest lookup, listing</td></tr><tr><td><code>__tests__/media-reference.test.ts</code></td><td>Factory methods, XOR validation, conversion helpers</td></tr><tr><td><code>__tests__/media-reference-schema.test.ts</code></td><td>Zod schema validation for media references</td></tr><tr><td><code>__tests__/binary-value-parser.test.ts</code></td><td>Binary value parsing and validation</td></tr><tr><td><code>__tests__/node-descriptor.test.ts</code></td><td><code>buildConfigSchema</code> Zod-to-JSON-Schema conversion and validation</td></tr><tr><td><code>__tests__/node-definition-assembly.test.ts</code></td><td><code>buildNodeDefinitionAssembly</code> assembly, port definition helpers, presets</td></tr></tbody></table>`,41)]))}const u=t(c,[["render",r]]);export{f as __pageData,u as default};
